args.sparql:
SELECT ?person ?personLabel ?followers
WHERE {
  ?person wdt:P2865 ?instagramAccount.
  ?person wdt:P1552 ?followers.
  OPTIONAL { ?person rdfs:label ?personLabel FILTER(LANG(?personLabel) = 'en') }
}
ORDER BY DESC(?followers)
LIMIT 1

SELECT ?person ?personLabel ?followers
WHERE {
  ?person wdt:P31 wd:Q5.  # Filter for humans
  ?person wdt:P2865 ?instagramAccount.
  ?person wdt:P1552 ?followers.
  OPTIONAL { ?person rdfs:label ?personLabel FILTER(LANG(?personLabel) = 'en') }
}
ORDER BY DESC(?followers)
LIMIT 1

SELECT ?person ?personLabel ?amount
WHERE {
  ?person wdt:P31 wd:Q5.
  ?person wdt:P2865 ?instagramAccount.
  ?person wdt:P1552 ?quantity.
  ?quantity wikibase:quantityAmount ?amount.
  OPTIONAL { ?person rdfs:label ?personLabel FILTER(LANG(?personLabel) = 'en') }
}
ORDER BY DESC(?amount)
LIMIT 1

